import{_ as e,o as p,c as r,a2 as o}from"./chunks/framework.BWuWLRhz.js";const n="/images/why-is-my-laptop-on/george-4.png",a="/images/why-is-my-laptop-on/george-6.png",s="/images/why-is-my-laptop-on/man-pushing-rock.png",g="/images/why-is-my-laptop-on/mechanical-man.png",i="/images/why-is-my-laptop-on/electric-man.png",m="/images/why-is-my-laptop-on/money-analogy-1024x721.png",l="/images/why-is-my-laptop-on/Fusion.png",h="/images/why-is-my-laptop-on/full-chain1.png",c="/images/why-is-my-laptop-on/george-clap.png",y="/images/why-is-my-laptop-on/pinit_fg_en_rect_gray_20.png",G=JSON.parse('{"title":"Why is My Laptop On?","description":"","frontmatter":{"title":"Why is My Laptop On?","titleZh":"我的笔记本为何还开着","date":"2014-03-12T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/03/why-is-my-laptop-on.html","slug":"why-is-my-laptop-on"},"headers":[],"relativePath":"posts/why-is-my-laptop-on.md","filePath":"posts/why-is-my-laptop-on.md","lastUpdated":1782886257000}'),u={name:"posts/why-is-my-laptop-on.md"};function w(_,t,f,b,d,k){return p(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="我的笔记本为何还开着-·-why-is-my-laptop-on" tabindex="-1">我的笔记本为何还开着 · Why is My Laptop On? <a class="header-anchor" href="#我的笔记本为何还开着-·-why-is-my-laptop-on" aria-label="Permalink to &quot;我的笔记本为何还开着 · Why is My Laptop On?&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/03/why-is-my-laptop-on.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/03/why-is-my-laptop-on.html</a> · 2014-03-12</p></blockquote><p>“我的笔记本电脑为什么开着?”这看上去不像是一个复杂的问题。</p><p>但当我这周试着回答它——<em>真正</em>回答它——的时候,我意识到我对能量这东西也就是勉强算了解得还不错而已。</p><p>然后我就想到了你。而以我对你的了解,你八成也就是勉强算了解得还不错。</p><p>于是我深吸了一口气,短暂地质疑了一下自己的存在意义,然后一头扎进了几个小时又几个小时关于能量的阅读中。最终的结果是,现在我这个人对能量的理解绝对可以说是——好吧也许不算真的很好——但比&quot;还不错&quot;要好。</p><p>我学到了很多,但因为我也搞不清你到底懂什么、不懂什么,我做了两件事:</p><p>1)我写了这篇文章,来彻底追问&quot;我的笔记本电脑为什么开着?&quot;这就是主文。</p><h2 id="_2-我还写了一篇附加文章-叫做-傻瓜能量指南-energy-for-dummies-里面把当今世界所有主要种类的能源——煤炭、石油、天然气、核能、生物质、水力、风能、太阳能、地热——都过了一遍-讲了它们是什么、怎么运作、以及各自在世界上扮演多大的角色。如果你想温习一下这方面的理解-可以去看看。" tabindex="-1">2)我还写了一篇附加文章,叫做 <a href="https://waitbutwhy.com/2014/03/energy-dummies.html" target="_blank" rel="noreferrer">傻瓜能量指南 (Energy for Dummies)</a>,里面把当今世界所有主要种类的能源——煤炭、石油、天然气、核能、生物质、水力、风能、太阳能、地热——都过了一遍,讲了它们是什么、怎么运作、以及各自在世界上扮演多大的角色。如果你想温习一下这方面的理解,可以去看看。 <a class="header-anchor" href="#_2-我还写了一篇附加文章-叫做-傻瓜能量指南-energy-for-dummies-里面把当今世界所有主要种类的能源——煤炭、石油、天然气、核能、生物质、水力、风能、太阳能、地热——都过了一遍-讲了它们是什么、怎么运作、以及各自在世界上扮演多大的角色。如果你想温习一下这方面的理解-可以去看看。" aria-label="Permalink to &quot;2)我还写了一篇附加文章,叫做 [傻瓜能量指南 (Energy for Dummies)](https://waitbutwhy.com/2014/03/energy-dummies.html),里面把当今世界所有主要种类的能源——煤炭、石油、天然气、核能、生物质、水力、风能、太阳能、地热——都过了一遍,讲了它们是什么、怎么运作、以及各自在世界上扮演多大的角色。如果你想温习一下这方面的理解,可以去看看。&quot;">​</a></h2><p>好了,所以我的笔记本电脑为什么开着?</p><p>为了充分回答这个问题,我在街上找了个四岁的小男孩,拿糖诱惑他,然后把他绑架了。现在,每当我以为自己给出了这个问题的答案,他就会问&quot;为什么?&quot;——因为四岁小孩就是干这事的——而这会逼着我们一路追问到<em>真正</em>的答案。我们就叫他乔治 (George)。大家跟他打个招呼。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/george-4.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="Little George"></a></strong></p><p>所以我对这个问题的第一个回答是:&quot;因为我把它开着。&quot;</p><p><strong>乔治:为什么?</strong></p><p>好问题,乔治。我把它开着是因为我得写这篇文章。嗯,不对,其实我刚才是随口一说——事实是我的笔记本电脑一直都开着。我基本上从来不关它。</p><p><strong>乔治:为什么?</strong></p><p>因为现代的笔记本电脑其实根本不需要关机。也因为我有点毛病,而且我爱上了我的笔记本电脑。</p><p><strong>乔治:为什么?</strong></p><p>因为我对精神刺激上瘾,而且完全没有自制力。</p><p><strong>乔治:为什么?</strong></p><p>因为我都32岁了,还在莫名其妙地反抗童年时代的权威。</p><p><strong>乔治:为什么?</strong></p><p>因为我就是个没那么有分量的男人。</p><p><strong>乔治:为什么?</strong></p><p>因为我在一个把我养得很软弱的世界里长大。我是个吉普赛人 (GYPSY)。</p><p><strong>乔治:为什么?</strong></p><p>等等。</p><p>这他妈的是在干嘛?这完全不是本来应该发生的事情啊。这篇文章应该是关于能量的。听着,乔治,我需要你调整一下你的提问方式。我希望你不要光问&quot;为什么?&quot;,而是更具体一点,把问题跟能量挂上钩。我们是在努力搞清楚能量是怎么回事。</p><p><strong>乔治:为什么?</strong></p><p>因为那比探讨我的个人缺陷有意思多了。</p><p><strong>乔治:为什么?</strong></p><p>不行。这样写不通。我要修改这幅画,把乔治改成六岁。我忘了四岁小孩是什么样子了。</p><p>好,他现在六岁了。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/george-6.png" target="_blank" rel="noreferrer"><img src="'+a+'" alt="Big George"></a></strong></p><p>再来一次。我的笔记本电脑开着,是因为有电流通过它。</p><p><strong>乔治:为什么笔记本电脑里有电流通过?</strong></p><p>因为它插在电源线上,电源线又插在墙上的插座里。</p><p><strong>乔治:为什么墙上的插座里有电?</strong></p><p>因为它连着纽约市的电网。</p><p><strong>乔治:为什么纽约市有电网?</strong></p><p>好吧,他这次其实提出了一个有趣的问题——为了更好地理解这一点,我们来快速回顾一下人类使用能源的历史。你可以把这段历史大致分成三个时代:</p><p><strong>1. 非常非常古老年代的能源 ——</strong> 用你的胳膊干重活,并且对此感到不爽</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/man-pushing-rock.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Human energy"></a></strong></p><p>史前人类还真没搞明白怎么做事。</p><p><strong>2. 相当古老年代的能源 ——</strong> 直接利用自然力量</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/mechanical-man.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Mechanical energy"></a></strong></p><p>在某个时刻,人类意识到他们可以把一些繁重的劳动外包出去,让自然力量替他们干活——一个令人激动的进展。最早的大规模例子是控制火,这最初发生在 12.5 万到 40 万年前之间(取决于你问谁)。更近一点,过去 5000 年间有大量证据表明人类使用风车、水坝以及其他工具把自然力量转化为有用的机械能,而从 18 世纪早期开始,像蒸汽机这样极为精巧的技术开始为船舶和火车提供动力。</p><p>这些都是<em>直接</em>使用自然力量能源的例子——也就是说,我们学会了各种各样利用自然能源的方法,但这些能源必须在被利用的当时当地就地使用。举个例子,过去的风车会转动,那种转动的力可以用来提水或磨谷,但它的极限也就止于机械物理转动能完成的事。直接利用能源在今天仍然很常见——想想停电时还能用的东西就明白了。你的炉子和暖气(如果用煤气)、你的马桶(靠重力冲水——直接倒一桶水进去就行)、木柴火或点燃的蜡烛、你的车——都是现代人类不通过中间环节、直接从自然中取得能源的例子。</p><p><strong>3. 现代的能源 ——</strong> 间接地、大规模地利用自然力量</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/electric-man.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="Electric energy"></a></strong></p><p>大约 100 年前,当人类学会发电、并通过电网把电能作为一种可控能量远距离输送到各处时,世界发生了翻天覆地的变化。这可能是人类历史上影响最深远的单一发展。</p><p>突然之间,巨量的能量可以以工业规模被释放出来,转化为电,输送到很远的地方,然后在用户方便的时候被转化成几乎任何形式的能量。国家一端熊熊燃烧的煤火,现在可以用来冻结另一端的冰块。而现代的风车能做的也远不止提东西或磨东西——它能发电,而电几乎可以用来做任何事。我的笔记本电脑能用,而它用的电可能来自煤炭燃烧、原子分裂、风吹、或者河流奔涌——对我来说无所谓。所有这些自然力量到达我这里时看起来都一样——一个把电倒进我插进去的任何东西里的插座。</p><p>在某种意义上,电对能量世界的作用,就像钱对价值世界的作用一样:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/money-analogy.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="Electricity is cash"></a></strong></p><p>所以嘛,这就是为什么纽约,以及地球上几乎每座城市,都有电网。</p><p><strong>乔治:那电网里为什么有电?</strong></p><p>因为它连着发电厂,发电厂发电,并把电送进电网。</p><p><strong>乔治:发电厂怎么发电?</strong></p><p>好,这时候正好可以提一下能量守恒定律 (Law of Conservation of Energy),它说的是能量既不能被创造也不能被消灭,只能被转化为不同的形式。这意味着人类无法「制造」能量,只能利用已有的自然力,把它们摆弄成对自己合适的形式。所以发电的唯一办法,就是把某种已经存在的能源转化成电能。</p><p>对于一座典型的发电厂,它可能属于以下几种类型:</p><p><strong>1) 某种可再生能源发电厂(即水电、风电、太阳能等)。</strong> 这些能源在全世界的电力中占比很小——在美国,它们大约占电力的 11%。</p><p><strong>2) 核电厂。</strong> 核能只占世界总能源的 2.8%,但在美国电力中占比不算低——约 21%。</p><p><strong>3) 化石燃料发电厂。</strong> 全世界总能源近 80% 来自化石燃料——<a href="https://waitbutwhy.com/2014/03/energy-dummies.html" target="_blank" rel="noreferrer">煤炭、石油和天然气</a>——而化石燃料发电厂大约占美国电力的三分之二。</p><p>出于这个原因,我打算按概率提示的那样假设——我笔记本电脑里的电可以追溯到某座化石燃料发电厂。这对你也适用——不管你在世界的哪个角落,你用来阅读这篇文章的设备之所以能开机,<em>大概率</em>都得归功于某座化石燃料发电厂。</p><p>那么回到 George 的问题——化石燃料发电厂是怎么发电的?</p><p>它是通过燃烧化石燃料来发电的,而在电力领域这种燃料要么是煤,要么是天然气(石油主要用作交通燃料,不用来发电)。发电厂燃烧煤或天然气,把大量的水烧开,让水蒸气咆哮着冲进一台涡轮机(一个大螺旋桨),推动它转动。涡轮机连着一根轴,轴上缠着一圈圈铜线,周围环绕着磁铁。涡轮机一转,铜线圈也跟着转,这就把电流沿着导线送出发电厂,进入城市电网,变成电。</p><p>所以,是燃烧的化石燃料——比如煤——最终点亮了我笔记本里的电。</p><p><strong>George: 可是你说能量不能被创造,只能转化——那煤燃烧时释放的能量,又是从哪儿来的呢?</strong></p><p>对一个六岁小孩来说不赖嘛。这就引出了下一个问题:「化石燃料是什么?」</p><p>化石燃料是由远古植物的遗骸构成的,这些植物通常来自石炭纪 (Carboniferous Period),那是 3 亿到 3.6 亿年前的一段时期,那时连恐龙都还没出现呢。</p><p>大多数植物死后会分解,体内的能量会在死后不久就释放出去。但在石炭纪,许许多多的植物、藻类和微生物死在沼泽里或者海里,沉到底部,被沙子、黏土和其他物质掩埋,能量就这样一路被保留了下来。经过数百万年,越来越多的沙石堆积在这些死去的生物之上,巨大的压力最终把它们变成了煤、石油或天然气。那些远古生物临死时带着的能量,<em>直到今天依然存在</em>,只是以化石燃料中化学能的形式保存着。</p><p>所以,是那些远古时代活着的植物体内的能量,今天被发电厂通过燃烧燃料(也就是燃烧反应)释放了出来。</p><p><strong>George: 那我们会把化石燃料用光吗?</strong></p><p>抱歉 George,这个问题你得去读<a href="https://waitbutwhy.com/2014/03/energy-dummies.html" target="_blank" rel="noreferrer">这篇文章的另一部分</a>才能找到答案,因为我不想写两遍。</p><p><strong>George: 好吧,那<em>那些</em>能量又是从哪儿来的?能量最开始是怎么进入那些远古植物体内的?</strong></p><p>跟今天能量进入植物的方式一样——光合作用。1</p><p>光合作用其实非常简单。以一棵树为例,它是这样运作的:</p><p>太阳照射在树上,把二氧化碳分解开来,碳留在树里构成它的实体,而氧气则作为副产品被释放出去。在这个分子分解的过程中,树吸收了太阳的能量(作为化学能),这些能量就留在了树里。当你烧一根木头时,你所做的其实就是<em>逆转这个过程</em>——把碳和氧重新合到一起,并在此过程中以火的形式释放出储存的太阳能量。火其实就是太阳的光和热,被木头吸收了很多年,终于被释放出来。</p><p>我们烧化石燃料时发生的事情跟这一模一样——只不过和木头不同的是,化石燃料在 3 亿多年前就吸收了太阳的能量,所以现在释放出来的是<em>远古的、3 亿年前的阳光</em>。</p><p>所以我的笔记本电脑和你的设备,都是被一个远古的太阳所驱动的——它的能量已经被死去的植物扣押了<em>漫长的岁月</em>。</p><p><strong>George:好,那笔记本里的能量来自远古的太阳——但<em>那个</em>能量又来自哪里?</strong></p><p>太阳的能量全部来自太阳中心正在进行的核聚变——原子在不可思议的压力下被挤到一起,直到它们合并成一个单独的原子,在这个过程中释放出大量能量。它和核裂变(核电站就是靠这个发电)正好相反,大概长这样:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/Fusion.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Nuclear Fusion"></a></strong></p><p>于是核聚变的能量爆发从太阳核心向外射出光子,然后这些光子灰不溜秋地花了大约 <a href="http://sunearthday.nasa.gov/2007/locations/ttt_sunlight.php" target="_blank" rel="noreferrer"><em>10 万年</em></a> 才到达太阳表面,但从那里到地球只要 8 分钟,这时它们才第一次可以被植物吸收。</p><p><strong>George:那<em>那个</em>能量——核聚变——又是从哪来的?</strong></p><p>核聚变之所以发生在恒星的核心,只是因为一颗恒星海量的物质在核心制造出了<em>极其强大的</em>引力压力——强到足以点燃核聚变。</p><p><strong>那什么是引力?</strong></p><p>你这小子还挺能问的,George。</p><p>引力就是弯曲的时空——是物质在时空里造出的一个&quot;凹陷&quot;——而像太阳这么大质量的物质造出来的,是一个非常深的凹陷。</p><p>所以<em>这才是</em>给我笔记本供电的能量的真正起源——太阳的质量在时空中造成了深深的凹陷,由此引发核聚变,10 万年后地球上的一株植物通过光合作用吸收了这份能量。这份能量随后被困在地下的死亡植物体内,经过漫长时间被挤压成像煤这样的化石燃料,3 亿年后被一位煤矿工人挖出来,运到燃煤发电厂,一把火烧掉——把远古太阳的光和热以火焰的形式释放出来。这团火在发电厂里把水烧开,把能量以蒸汽的形式释放出来,推动发电机里的涡轮机转动,把能量以电的形式射入电网,然后当我插上电源线的时候从我墙上的插座里流出来进入我的电脑,现在我的笔记本就开机了。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/full-chain1.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="Why is my laptop on?"></a></strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/george-clap.png" target="_blank" rel="noreferrer"><img src="'+c+`" alt="george clapping"></a></strong></p><p>谢啦,George。我刚才确实挺牛的,没错。</p><p>总之,这段把我笔记本的电力追溯到远古太阳引力的漫长过程,也同样适用于非电能——你的车在跑(你车盖底下那堆乱七八糟的东西其实就是个小型发电厂,烧汽油,汽油来自石油,释放出它远古的能量)、一根蜡烛在燃烧(当你意识到蜡是从地下石油来的、里面储存着 3 亿年前的太阳能量、<em>终于</em>在你点燃它的那一刻以火焰形式释放出来,这蜡烛是不是酷了 N 倍),或者你生活中几乎任何其他种类的能量。</p><p>甚至连你自己的身体也算。我为什么能用手指打这篇博文?因为我的身体有能量,来自我吃过的食物,食物要么是植物、要么是从植物那儿获取能量的动物,这又把我们带回到光合作用——只不过这一次是<em>近期的</em>光合作用,也就是说给我手指供能的阳光相当新鲜(但由于光子延迟,产生这些阳光的核聚变,以及迫使那次聚变发生的引力,依旧是 10 万年前的老古董)。</p><p>就是这么回事,George——玩得开心吗?</p><p><strong>George:开心。不过等等——为什么物质会在时空中造成凹陷?</strong></p><h2 id="太好了-我很高兴你玩得开心-george。现在跑开吧。" tabindex="-1">太好了!我很高兴你玩得开心,George。现在跑开吧。 <a class="header-anchor" href="#太好了-我很高兴你玩得开心-george。现在跑开吧。" aria-label="Permalink to &quot;太好了!我很高兴你玩得开心,George。现在跑开吧。&quot;">​</a></h2><p>1. 光合作用简直不可思议。整个食物链无非就是生物从别的生物那儿偷能量——有时候是一只动物吃掉一株植物或另一只动物,有时候温和一点,比如一只蜜蜂偷走花的花蜜。但我们很少停下来问一句:「这些能量最初到底是怎么进入食物链的?」当然是通过光合作用啦。植物搞明白了怎么把太阳的能量变成「食物」,而这正是整个食物链所有能量的源头。光合作用是自然能量进入生物世界的关键时刻——我平时想这事想得还不够多。</p><p>[读者 David B. 指出还有另一种能量进入食物链的方式:「在深海海底有热泉喷口,那里整个生态系统靠一种叫做化能合成 (chemosynthesis) 的过程存活。在那里,化能自养生物利用无机能源(比如硫化氢)驱动食物网。」]</p><p><em>想快速了解今天世界上所有相关能源,请看 Wait But Why 的速成课<a href="https://waitbutwhy.com/2014/03/energy-dummies.html" target="_blank" rel="noreferrer">《能源傻瓜指南》(Energy for Dummies)</a></em>。</p><p><strong>相关 Wait But Why 文章</strong></p><h2 id="把时间放进视角里看看ai-革命-通往超级智能之路241-万亿美元能买啥" tabindex="-1"><a href="https://waitbutwhy.com/2013/08/putting-time-in-perspective.html" target="_blank" rel="noreferrer">把时间放进视角里看看</a><a href="https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html" target="_blank" rel="noreferrer">AI 革命:通往超级智能之路</a><a href="https://waitbutwhy.com/2014/03/combined-wealth-world.html" target="_blank" rel="noreferrer">241 万亿美元能买啥?</a> <a class="header-anchor" href="#把时间放进视角里看看ai-革命-通往超级智能之路241-万亿美元能买啥" aria-label="Permalink to &quot;[把时间放进视角里看看](https://waitbutwhy.com/2013/08/putting-time-in-perspective.html)
[AI 革命:通往超级智能之路](https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html)
[241 万亿美元能买啥?](https://waitbutwhy.com/2014/03/combined-wealth-world.html)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,欢迎注册我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章一出来我们就发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/03/why-is-my-laptop-on.html&amp;description=Why%20is%20My%20Laptop%20On?" target="_blank" rel="noreferrer"><img src="`+y+'" alt=""></a></p>',107)])])}const W=e(u,[["render",w]]);export{G as __pageData,W as default};
